import{_ as t,o as a,c as i,a3 as n}from"./chunks/framework.BveOjhN0.js";const m=JSON.parse('{"title":"Module Licensing","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Module Licensing | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/architecture/module-licensing"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Module Licensing | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/architecture/module-licensing"}]]},"headers":[],"relativePath":"architecture/module-licensing.md","filePath":"architecture/module-licensing.md","lastUpdated":1784905729000}'),o={name:"architecture/module-licensing.md"};function l(r,e,s,d,c,u){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="module-licensing" tabindex="-1">Module Licensing <a class="header-anchor" href="#module-licensing" aria-label="Permalink to &quot;Module Licensing&quot;">​</a></h1><p>Every module is designed to support <strong>independent licensing</strong>.</p><p>This page documents the <strong>architectural convention</strong> for how modules should be designed over the long term. It is not a claim that every planned module is already sold, priced, or enforced separately in production. For the current entitlements model and middleware behavior, see <a href="/developer-guide/entitlements">Entitlements</a>.</p><blockquote><p><strong>Important</strong></p><p>This is documentation of the licensing <em>convention</em>. It does <strong>not</strong> change billing code, marketplace implementation, pricing, or catalog rows.</p></blockquote><h2 id="licensing-postures" tabindex="-1">Licensing postures <a class="header-anchor" href="#licensing-postures" aria-label="Permalink to &quot;Licensing postures&quot;">​</a></h2><p>A module may be:</p><table tabindex="0"><thead><tr><th>Posture</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>Included by default</strong></td><td>Installed automatically for workspaces (typically <code>is_default_included</code>)</td></tr><tr><td><strong>Free</strong></td><td>Available without charge, but not necessarily auto-included for every workspace</td></tr><tr><td><strong>Billable</strong></td><td>Offered as a paid marketplace module</td></tr></tbody></table><p>These postures can change over product releases without redesigning the module’s internal architecture.</p><h2 id="long-term-rules" tabindex="-1">Long-term rules <a class="header-anchor" href="#long-term-rules" aria-label="Permalink to &quot;Long-term rules&quot;">​</a></h2><p>Documented product and engineering expectations:</p><ol><li><strong>Some modules may always remain free</strong> — for example core CRM capabilities the platform chooses to keep included or non-billable.</li><li><strong>Some modules may become billable in future releases</strong> — schema and catalog fields already anticipate <code>is_billable</code>, pricing, and subscription <code>source</code> without requiring a redesign.</li><li><strong>Future modules must be designed to support independent licensing</strong> — do not hard-code assumptions that Module A is always free, always included, or always bundled with Module B.</li><li><strong>This is an architectural convention</strong> — teams should design modules as independently licensable even when the first release ships them as default-included or free.</li></ol><h2 id="design-implications-for-engineers" tabindex="-1">Design implications for engineers <a class="header-anchor" href="#design-implications-for-engineers" aria-label="Permalink to &quot;Design implications for engineers&quot;">​</a></h2><p>When building a module:</p><ul><li>Gate routes and UI with <code>module:{slug}</code> <strong>and</strong> Spatie permissions — never fold licensing into role permissions.</li><li>Keep the module installable on its own (aside from declared <a href="./module-dependencies">dependencies</a>).</li><li>Avoid embedding “always available” assumptions for sibling modules.</li><li>Prefer catalog + subscription + middleware patterns already used by Leads and Tasks.</li><li>Treat Marketplace activation and workspace subscriptions as the licensing surface; do not invent a parallel plan/feature/limit system (forbidden under <a href="/getting-started/platform-freeze">platform freeze</a>).</li></ul><h2 id="relationship-to-dependencies" tabindex="-1">Relationship to dependencies <a class="header-anchor" href="#relationship-to-dependencies" aria-label="Permalink to &quot;Relationship to dependencies&quot;">​</a></h2><p>Module dependencies and module licensing are related but distinct:</p><table tabindex="0"><thead><tr><th>Concern</th><th>Question</th></tr></thead><tbody><tr><td>Dependency</td><td>Does this module need another module’s capability to work?</td></tr><tr><td>Licensing</td><td>Is this module included, free, or billable for a workspace?</td></tr></tbody></table><p>A required dependency may itself be free or billable. Optional integrations must degrade gracefully when the optional module is not licensed/installed.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./module-architecture">Module Architecture</a></li><li><a href="./module-dependencies">Module Dependencies</a></li><li><a href="/developer-guide/entitlements">Entitlements</a></li><li><a href="/developer-guide/billing-engine">Billing Engine</a></li><li><a href="/getting-started/platform-freeze">Platform Freeze</a></li></ul>',20)])])}const g=t(o,[["render",l]]);export{m as __pageData,g as default};
